window.__QUIZ_DATA__=[{"id":"theory>Biology>2006>1>a>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"List the functions of a typical foliage leaf.","images":[],"marking_scheme":"The functions of typical foilage leaf include:  1. Respiration  2. Excretion  3. Exchange of gases  4. Photosynthesis/Manufacture of food  5. Transpiration","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>1>a>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name three types of leaf modifications giving one example in each case.","images":[],"marking_scheme":"Modification of leaves and examples.  Leaves can be modified into the following  1. For (food) storage: Examples: Onion, Garlic  2. Leaf tendrils: Example: Gloriosa  3. Leaf spines: Examples: Cactus, Opuntia, Euphorbia  4. Leaf hooks: Examples: Bignonia  5. Vegetative propagation: Bryophyllum  6. Animal traps: Examples: Venus fly trap, Pitcher plants, Bladder wort, Sound dew  7. Protective scale leaves: Examples: Onions, Shallots, Canna.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>1>b","subject":"Biology","year":"2006","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Make a diagram 8 - 10 cm long, of the female reproductive part of a flowering plant and label fully.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7","difficulty":"3"},{"id":"theory>Biology>2006>1>c","subject":"Biology","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"Name three plants that are pollinated by insects.","images":[],"marking_scheme":"Plants pollinated by insects include:  1. Cowpea - (Vigna unguiculata)  2. Hibiscus - (Crotalaria spp)  3. Orchid  4. Sunflower","marks":"3","difficulty":"2"},{"id":"theory>Biology>2006>2>a>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Describe three features of a typical vertebra.","images":[],"marking_scheme":"The features of a typical vertebra include:  Centrum - This is a solid piece of bone in the spinal cord  Neural canal - This is a passage of the spinal cord  Neural arch - This forms an arch over the centrum and surrounds the neural carnal.  Neural spine - Projects upward from the neural arch  Transverse processes - These are projections from the sides of the neural arch  Facets - Articulate surface for adjacent vertebrae","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>2>a>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Name three types of skeletons found in animals, and in each case name one animal which possesses it.","images":[],"marking_scheme":"The types of skeleton include:  - Exoskeleton: Crab, millipede, centipede, insects, etc  - Endoskeleton: Mammals, fish, lizard, bird  - Hydro-skeleton: Worms, sea anemone, slug, earthworm, caterpillars etc","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>2>b>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State four functions of the mammalian skeleton.","images":[],"marking_scheme":"The functions of mammalian skeleton include:  1. For protection   2. For movement/locomotion  3. Support/rigidity  4. For breathing movement  5. For production of red blood cells","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>2>b>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Name four types of joints found in the mammalian skeleton.","images":[],"marking_scheme":"The types of joints in mammals include:  1. Fixed joint  2. Gliding/sliding joint  3. Ball and socket joint  4. Hinge joint  5. Pivot joint","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>3>a>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Write short note on ecosystem","images":[],"marking_scheme":"The term \"ecosystem\" can exhibit the following characteristics   1. It is a self-supporting unit or system  2. It consists of all living organisms and non-living factors   3. The living organisms constitute the biotic component  4. Each component of an ecosystem influence the properties of others  5. The non- living factors constitute the abiotic components","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>3>a>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"Write short note on population","images":[],"marking_scheme":"Population refers to the total number of organisms or individual of the same species living together within a habitat at a particular time.  The size of the population varies due to different factors which may include: natality, mortality, emigration, immigration.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>3>a>iii","subject":"Biology","year":"2006","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"Write short note on ecological succession in plants","images":[],"marking_scheme":"Ecological succession in plants.  Ecological succession is the orderly series of changes occurring in biotic communities, over a long period of time until a stable or  climax community is established.  Ecological succession in plants usually commences in a newly formed open farmland which is usually as a result of human activities, natural disasters or catastrophes. The pioneer/primary colonizers have short life cycle which got replaced by other plants thus derive nutrients from their remains, the latter/secondary colonizers have longer life spans.  The initial space of a succession is rapid but it gradually slows down unit a stable/climax community is reached.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>3>b","subject":"Biology","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"List five ways by which Nitrogen can be made available to the soil for plant growth.","images":[],"marking_scheme":"The following are the ways through which nitrogen can be made available in the soil.  1. Through nitrogen fixation  2. Through thunderstorm and lightning  3. Through putrefaction/decay of organic matter  4. Through nitrification  5. Through fertilizer application  6. Through the application of organic fertilizers/farmyard manure","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>4>a","subject":"Biology","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Explain the term conservation of natural resources.","images":[],"marking_scheme":"Conservation is the wise use/safe-keeping/management of natural resources for benefit of mankind, to ensure their continuous availability and to avoid their extinction.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>4>b>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"List seven methods of soil conservation.","images":[],"marking_scheme":"Methods of soil conservation  The soil can be conserved through the following methods.  1. Planting grasses/legumes/ any other named cover crops  2. Crops must be planted on ridges across slopes  3. Avoiding/Preventing bush burning  4. Practising shifting cultivation/bush fallowing/ crop rotation  5. Addition of manure/fertilizer to the top soil.  6. Spreading a layer of vegetable material on cultivated farmland (this process is known as mulching)  7. Constructing ridges across the slope of the land at intervals (this process is known as contour ridging)  8. Planting trees/reafforestation  9. Prevention of overgrazing.","marks":"10","difficulty":"2"},{"id":"theory>Biology>2006>4>b>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Name four other natural resources that may be conserved.","images":[],"marking_scheme":"Natural resources that can be conserved.  The followings are natural resources that can be conserved   1. Water   2. Forest  3. Wild life  4. Mineral resources   5. Genetic material/genes - this is usually done to avoid mutation  6. Petroleum/Coal/Gas/Fossil/Fuel.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>4>c","subject":"Biology","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"State three factors which negatively affect conservation of forest in West Africa.","images":[],"marking_scheme":"Factors that negatively affect conservation of forest in West Africa.  1. Uncontrolled lumbering of forest trees  2. Lack of afforestation  3. Bush burning  4. Non-enforcement of conservation laws  5. Lack of knowledge on conservation awareness  6. Use of firewood or charcoal for fuel  7. Air or soil pollution","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>4>d","subject":"Biology","year":"2006","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"Describe what happens during the denitrification stage of the nitrogen cycle.","images":[],"marking_scheme":"Denitrification stage of the Nitrogen cycle  (In the soil) Denitrifying bacteria/named bacteria / certain fungi                                Convert nitrates in the soil to nitrites                                Some bacteria / pseudomonas spp which converts nitrites into gaseous nitrogen.                               The gaseous nitrogen is released into the atmosphere                               Resulting in reduced soil fertility","marks":"20","difficulty":"3"},{"id":"theory>Biology>2006>5>a","subject":"Biology","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"What is a hormone?","images":[],"marking_scheme":"A hormone is a chemical substance produced in small quantities by endocrine or ductless glands and carried to all parts of the body or targeted organs by blood stream or vascular system, where it produces a response.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>5>b","subject":"Biology","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Outline the role played by adrenaline in an emergency.","images":[],"marking_scheme":"Role of adrenaline in an emergency  - Any emergency experienced by an animal causes a sudden fright, this leads to the release of adrenaline in the blood, which stimulates the sympathetic nervous system and consequently many different organs.  - The rate of heartbeat is increases.  - Similarly there is increase in the body sugar/conversion of liver glycogen into glucose.  - The muscular tone is increased, i.e there is resistance to fatigue   - The pupils of the eyes dilate and the visceral muscles are affected  - The animal reacts quickly and energetically.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>5>c","subject":"Biology","year":"2006","type":"Theory","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : NERVOUS COORDINATION~~CONCEPT OF LIVING : HORMONAL COORDINATION","question":"In a tabular form, list five differences between hormonal co-ordination and nervous co-ordination.","images":[],"marking_scheme":"Differences between hormonal co-ordination and nervous co-ordination.  Hormonal Co-ordination Nervous Co-ordination Involves transmission of chemical substances in the blood stream.Involves transmission of electrical impulses and chemical substances by the nervous system  Response to stimulus is slowerResponse to stimulus is faster Hormones are secreted into the blood and carried to any part of the body.Nerve impulses are transmitted to a particular set of neurones  The target is usually far from the site of productionTarget organ may be near or farResponses may last for a long timeResponses are short-lived.Secretion of hormones and their actions are involuntaryNervous actions and  their responses are voluntaryHormonal co-ordination occurs in both plants and animalsNervous co-ordination occurs only in animals","marks":"5","difficulty":"3"},{"id":"theory>Biology>2006>5>d","subject":"Biology","year":"2006","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"Name **three* animal hormones and two plant hormones.","images":[],"marking_scheme":"Animal Hormones  1. Somatotrophic hormone  2. Prolactin  3. Gonatotrophic  4. Thyroxine  5. Thyrotrophic hormone  6. Oxytocine  7. Anti-diuretic hormone (ADH)  8. Parathormone  9. Adrenaline  10. Insulin  11. Oestrogen  12. Progesterone    Plant Hormones  1. IAA/Indola-3-Acetic acid  2. 2 - 4 D/ 2 - 4 Dichlorophenoxy-acetic acid  3. Gibberethins  4. Cytokinnins/kinins  5. Abscisin/Abscisic acid  6. Benzoic acid  7. NAA/Naphtalone acetic acid  8. IBA/Indolebutyric acid  9. Ethylene  10. Vermalin","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>6>a>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Briefly explain the term respiration.","images":[],"marking_scheme":"Respiration is the oxidation of food substances in the cell, (particularly in the mitochondria) with the release of chemical energy (ATP), carbon(iv)oxide and water for aerobic or chemical energy, alcohol and water for anaerobic.","marks":"5","difficulty":"1"},{"id":"theory>Biology>2006>6>a>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Name the two types of respiration and write a balanced equation to summarize each of them.","images":[],"marking_scheme":"Aerobic Respiration  Anaerobic Respiration    * Aerobic respiration  C6H12O6 + 6O2 \u2192 6CO2 + 6H2O + Energy    * Anaerobic respiration  C6H12O6 \u2192 2C2H5OH + 2CO2 + Energy","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>6>b>i","subject":"Biology","year":"2006","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Outline the mechanisms involved in Inhalation.","images":[],"marking_scheme":"During the process of inhalation, the following occur  1. External intercostal muscles contract  2. Internal intercostal muscles relax  3. Ribs move up and outwards  4. Diaphragm contracts and flattens  5. Volume of thorax cavity increases   6. Air pressure decreases   7. Air rushes into the lungs from the atmosphere","marks":"5","difficulty":"2"},{"id":"theory>Biology>2006>6>b>ii","subject":"Biology","year":"2006","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Outline the mechanisms involved in exhalation in human beings.","images":[],"marking_scheme":"Exhalation  1. External intercostal muscles relax   2. Internal intercostal muscles contract  3. Ribs move down and inwards   4. Diaphragm relaxes/ becomes dome-shaped   5. Volume of thoracic cavity decreases   6. Air pressure increases   7. Air rushes out of lungs into the atmosphere.","marks":"5","difficulty":"2"}];